// Common OOM scenarios and their area:

// 1. Heap: too many live objects
// java.lang.OutOfMemoryError: Java heap space
// Fix: -Xmx512m, find memory leak with heap dump

// 2. Metaspace: too many loaded classes (common with CGLIB, Groovy)
// java.lang.OutOfMemoryError: Metaspace
// Fix: -XX:MaxMetaspaceSize=256m

// 3. Stack overflow: infinite/very deep recursion
// java.lang.StackOverflowError
// Fix: -Xss4m, or rewrite as iterative

// 4. Direct memory (NIO buffers)
// java.lang.OutOfMemoryError: Direct buffer memory
// Fix: -XX:MaxDirectMemorySize=256m

// Useful flags:
// -Xms256m -Xmx1g   (initial / max heap)
// -Xss1m            (thread stack size)

// Inspect class loader hierarchy
Class<?> c = ArrayList.class;
System.out.println(c.getClassLoader());         // null (Bootstrap)

Class<?> myClass = MyApp.class;
System.out.println(myClass.getClassLoader());    // AppClassLoader
System.out.println(myClass.getClassLoader()
    .getParent());                               // PlatformClassLoader

// Load a class dynamically
Class<?> clazz = Class.forName("com.example.MyPlugin");
// ^ uses calling class's loader by default

// Load with a specific loader
URLClassLoader loader = new URLClassLoader(
    new URL[]{ new File("plugin.jar").toURI().toURL() }
);
Class<?> plugin = loader.loadClass("com.example.MyPlugin");
loader.close(); // important: release the jar file handle

// Observe JIT in action
// Flag: -XX:+PrintCompilation
// Output format: timestamp  compile-id  flags  class::method  size
// e.g.: 1234  42   !   java.util.HashMap::get (35 bytes)
// '!' = has exception handler, 's' = synchronised, 'n' = native

// Flag: -XX:CompileThreshold=10000 (default)
// Method compiled after ~10,000 invocations (lower = faster warm-up)

// Escape analysis — JIT may allocate on stack instead of heap
// if it can prove an object doesn't escape the method:
public int sum(int a, int b) {
    Point p = new Point(a, b); // may be stack-allocated by JIT
    return p.x + p.y;
}

// Inlining — small methods are inlined at call sites
// -XX:MaxInlineSize=35 (methods <= 35 bytes are inlined)
// -XX:+PrintInlining to observe
